'use client'
import { cn } from '@cascivo/core'
import { Sparkline } from '@cascivo/charts'
import type { HTMLAttributes } from 'react'
import { AutoGrid } from '../../auto-grid/auto-grid'
import styles from './stats-band.module.css'

export interface StatItem {
  label: string
  value: string
  delta?: string
  trend?: number[]
}

export interface StatsBandProps extends HTMLAttributes<HTMLElement> {
  stats: StatItem[]
  /** Accessible label for the stats region when no visible heading is shown. */
  'aria-label'?: string
  className?: string | undefined
}

export function StatsBand({ stats, className, ...props }: StatsBandProps) {
  return (
    <section
      className={cn(styles['stats-band'], className)}
      aria-label={props['aria-label'] ?? 'Key metrics'}
      {...props}
    >
      <div className={styles['inner']}>
        <AutoGrid min="12rem" gap={4}>
          {stats.map((stat, i) => (
            <div key={i} className={styles['stat']}>
              <div className={styles['stat-main']}>
                <span className={styles['value']}>{stat.value}</span>
                {stat.trend && (
                  <Sparkline
                    data={stat.trend}
                    label={`${stat.label} trend`}
                    width={80}
                    height={28}
                  />
                )}
              </div>
              {stat.delta && <span className={styles['delta']}>{stat.delta}</span>}
              <span className={styles['label']}>{stat.label}</span>
            </div>
          ))}
        </AutoGrid>
      </div>
    </section>
  )
}

@layer cascivo.component {
  .stats-band {
    padding-block: var(--cascivo-space-8);
    padding-inline: var(--cascivo-space-4);
    border-block: 1px solid var(--cascivo-color-border);
    background-color: var(--cascivo-surface-subtle);
  }

  .inner {
    max-inline-size: 90rem;
    margin-inline: auto;
  }

  .stat {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
    padding-inline: var(--cascivo-space-4);
    border-inline-start: 1px solid var(--cascivo-color-border);
    min-inline-size: 0;
  }

  .stat-main {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-3);
  }

  .value {
    font-size: var(--cascivo-text-2xl);
    font-weight: var(--cascivo-font-bold);
    font-family: var(--cascivo-font-mono);
    line-height: 1;
  }

  .delta {
    font-size: var(--cascivo-text-sm);
    font-family: var(--cascivo-font-mono);
    color: var(--cascivo-text-secondary);
  }

  .label {
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-text-secondary);
  }
}
